// ─── Single Tile Component ───
function ProfessionalTile({ tile }) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      className="rpp-tile"
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onTouchStart={() => setHovered(true)}
      onTouchEnd={() => setTimeout(() => setHovered(false), 1800)}
      style={{ perspective: "900px", perspectiveOrigin: "50% 20%", cursor: "pointer", width: "100%" }}
    >
      {/* Brochure */}
      <div style={{
        width: "100%",
        background: "#FDFAF5",
        borderRadius: "5px",
        border: "1px solid rgba(184,154,90,0.40)",
        position: "relative",
        transform: "rotateX(28deg)",
        transformOrigin: "bottom center",
        transformStyle: "preserve-3d",
        boxShadow: hovered
          ? "0 4px 0 1px rgba(155,132,78,0.20), 0 8px 0 1px rgba(130,110,60,0.11), 0 32px 64px rgba(18,36,63,0.30)"
          : "0 4px 0 1px rgba(155,132,78,0.20), 0 8px 0 1px rgba(130,110,60,0.11), 0 20px 44px rgba(18,36,63,0.22)",
        display: "flex",
        flexDirection: "column",
        transition: "box-shadow 0.4s ease",
      }}>

        {/* Stacked pages — pseudo-elements done as divs */}
        <div style={{ position: "absolute", inset: 0, background: "#F0EAE0", borderRadius: "5px", transform: "translateY(5px)", zIndex: -1 }} />
        <div style={{ position: "absolute", inset: 0, background: "#E5DED3", borderRadius: "5px", transform: "translateY(10px)", zIndex: -2 }} />

        {/* Corner flourishes */}
        {["tl","tr","bl","br"].map(pos => (
          <div key={pos} style={{
            position: "absolute",
            width: 14, height: 14,
            top: pos.startsWith("t") ? 8 : "auto",
            bottom: pos.startsWith("b") ? 8 : "auto",
            left: pos.endsWith("l") ? 8 : "auto",
            right: pos.endsWith("r") ? 8 : "auto",
            borderTop: pos.startsWith("t") ? "1.5px solid #b89a5a" : "none",
            borderBottom: pos.startsWith("b") ? "1.5px solid #b89a5a" : "none",
            borderLeft: pos.endsWith("l") ? "1.5px solid #b89a5a" : "none",
            borderRight: pos.endsWith("r") ? "1.5px solid #b89a5a" : "none",
            pointerEvents: "none",
            zIndex: 50,
          }} />
        ))}

        {/* Card inner */}
        <div style={{ padding: "10px 8px 0", perspective: "700px", perspectiveOrigin: "50% 100%", transformStyle: "preserve-3d", overflow: "visible", flex: 1, display: "flex", flexDirection: "column" }}>

          {/* Photo hinge */}
          <div style={{
            width: "100%",
            transformOrigin: "bottom center",
            transform: hovered ? "rotateX(-33deg)" : "rotateX(0deg)",
            transition: "transform 0.72s cubic-bezier(0.33,1,0.68,1)",
            backfaceVisibility: "hidden",
            display: "block",
            lineHeight: 0,
            fontSize: 0,
            overflow: "visible",
          }}>
            <img
              src={IMAGES[tile.key]}
              alt={tile.title}
              style={{
                display: "block",
                width: "100%",
                height: "auto",
                aspectRatio: "560/420",
                objectFit: "cover",
                margin: 0,
                filter: hovered
                  ? "drop-shadow(-3px 14px 28px rgba(18,36,63,0.40))"
                  : "drop-shadow(0 2px 8px rgba(18,36,63,0.16))",
                transition: "filter 0.5s ease",
                verticalAlign: "bottom",
              }}
            />
          </div>

          {/* Text area */}
          <div style={{ position: "relative", marginTop: 0, paddingTop: 0, height: 130, flexShrink: 0, display: "flex", flexDirection: "column", justifyContent: "flex-start", overflow: "hidden" }}>

            {/* Static content */}
            <div style={{ padding: "12px 10px 0", opacity: hovered ? 0 : 1, transition: "opacity 0.15s ease" }}>
              <span style={{
                display: "block", fontSize: 11, fontWeight: 700,
                letterSpacing: "0.18em", textTransform: "uppercase",
                color: "#b89a5a", marginBottom: 5,
                whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                fontFamily: "'Montserrat', sans-serif",
              }}>{tile.pill}</span>
              <h3 style={{
                fontFamily: "'Cormorant Garamond', serif",
                fontWeight: 700, fontSize: 24,
                color: "#12243F", lineHeight: 1.15, margin: 0,
              }}>{tile.title}</h3>
            </div>

            {/* Hover panel */}
            <div style={{
              position: "absolute", inset: 0,
              background: "rgba(10,20,46,0.97)",
              display: "flex", flexDirection: "column",
              alignItems: "center", justifyContent: "center",
              padding: 14, gap: 12,
              opacity: hovered ? 1 : 0,
              transition: "opacity 0.28s ease 0.15s",
              zIndex: 30,
              overflow: "hidden",
            }}>
              <p style={{
                fontFamily: "'Montserrat', sans-serif",
                fontWeight: 600, fontSize: 14, color: "#FFFFFF",
                textAlign: "center", lineHeight: 1.5, width: "100%", margin: 0,
              }}>{tile.tagline}</p>
              <span style={{
                fontFamily: "'Montserrat', sans-serif",
                fontSize: 11, fontWeight: 700,
                letterSpacing: "0.10em", textTransform: "uppercase",
                color: "#d4b87a",
                borderBottom: "1px solid rgba(212,184,122,0.6)",
                paddingBottom: 2, whiteSpace: "nowrap",
                cursor: "pointer",
              }}>{tile.cta} →</span>
            </div>

          </div>
        </div>

        {/* Footer */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "11px 12px 12px",
          borderTop: "1.5px solid rgba(184,154,90,0.28)",
          background: "#FDFAF5",
          borderRadius: "0 0 5px 5px",
          gap: 8, position: "relative", zIndex: 40, flexShrink: 0, minHeight: 54,
        }}>
          <span style={{
            fontFamily: "'Montserrat', sans-serif",
            fontSize: 11, fontWeight: 700,
            letterSpacing: "0.04em", textTransform: "uppercase",
            color: "#1a3a6b", lineHeight: 1.4, flex: 1,
          }}>Information &amp; Featured Providers</span>
          <div style={{
            marginLeft: "auto", width: 30, height: 30,
            border: "1.5px solid #1a3a6b", borderRadius: "50%",
            display: "flex", alignItems: "center", justifyContent: "center",
            background: hovered ? "#1a3a6b" : "transparent",
            transition: "background 0.25s", flexShrink: 0,
          }}>
            <svg width="12" height="12" viewBox="0 0 14 14" fill="none"
              stroke={hovered ? "#fff" : "#1a3a6b"} strokeWidth="2.2"
              strokeLinecap="round" strokeLinejoin="round"
              style={{ transform: hovered ? "translateX(1px)" : "none", transition: "stroke 0.25s, transform 0.25s" }}>
              <path d="M2 7h10M7 2l5 5-5 5"/>
            </svg>
          </div>
        </div>

      </div>
    </div>
  );
}

